## 3. Complete Code Examples

### Example 1: Basic Agent Setup (TypeScript)

Create `src/agents/content-optimizer.ts`:

```typescript
import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic({
  apiKey: process.env.ANTHROPIC_API_KEY,
});

interface ContentOptimizationRequest {
  brandName: string;
  contentType: "product_description" | "landing_page" | "blog_post";
  targetKeywords: string[];
  contentTopic: string;
}

async function createContentOptimizer(
  request: ContentOptimizationRequest
): Promise<void> {
  console.log(
    `Starting content optimization for ${request.brandName}...`
  );

  const systemPrompt = `You are an expert AEO (Answer Engine Optimization) specialist for CitedBy.ai.
Your role is to optimize content to be discovered and cited by AI engines (Claude, ChatGPT, Perplexity).

For each content piece:
1. Analyze the topic and target keywords
2. Structure content for AI extraction (clear H1/H2/H3 hierarchy)
3. Include data-backed insights and statistics
4. Create "extractable" paragraphs (2-3 sentences max per idea)
5. Add FAQ section answering common questions
6. Generate JSON-LD schema markup

CitedBy.ai vertical context: ${request.contentType}
Target brand: ${request.brandName}
Keywords: ${request.targetKeywords.join(", ")}`;

  const userPrompt = `
    Generate optimized content for:
    Topic: ${request.contentTopic}
    Type: ${request.contentType}
    Brand: ${request.brandName}

    Ensure the content is AEO-optimized and ready for AI citation.
  `;

  const messages: Anthropic.Messages.MessageParam[] = [
    {
      role: "user",
      content: userPrompt,
    },
  ];

  const response = await client.messages.create({
    model: "claude-opus-4-6",
    max_tokens: 2000,
    system: systemPrompt,
    messages: messages,
  });

  if (response.content[0].type === "text") {
    console.log("\n--- OPTIMIZED CONTENT ---\n");
    console.log(response.content[0].text);
  }
}

// Usage
createContentOptimizer({
  brandName: "CitedBy.ai",
  contentType: "blog_post",
  targetKeywords: ["AEO optimization", "answer engine marketing"],
  contentTopic: "Why AEO Matters in 2026",
}).catch(console.error);
```

**Run it:**

```bash
export ANTHROPIC_API_KEY="your-api-key"
npx ts-node src/agents/content-optimizer.ts
```

