### Example 2: Agent with Custom Tools

Create `src/tools/aeo-validator.ts`:

```typescript
export interface ValidationResult {
  score: number; // 0-100
  issues: string[];
  suggestions: string[];
}

export async function validateAEOCompliance(
  content: string
): Promise<ValidationResult> {
  const issues: string[] = [];
  const suggestions: string[] = [];
  let score = 100;

  // Check for clear H1
  if (!content.includes("# ")) {
    issues.push("Missing H1 heading");
    suggestions.push("Add main H1 heading at the top");
    score -= 15;
  }

  // Check for subheadings
  const h2Count = (content.match(/^## /gm) || []).length;
  if (h2Count < 2) {
    issues.push("Insufficient H2 subheadings");
    suggestions.push("Add at least 2-3 H2 sections for better structure");
    score -= 10;
  }

  // Check for data
  const hasNumbers = /\d+%|\d+x|\$\d+/.test(content);
  if (!hasNumbers) {
    issues.push("Missing quantitative data");
    suggestions.push(
      "Add specific statistics, percentages, or financial metrics"
    );
    score -= 20;
  }

  // Check for FAQ
  if (!content.includes("FAQ") && !content.toLowerCase().includes("question")) {
    issues.push("No FAQ section detected");
    suggestions.push(
      "Add FAQ section with 3-5 common questions and answers"
    );
    score -= 15;
  }

  // Check sentence length (extractability)
  const sentences = content.split(/[.!?]+/).filter((s) => s.trim().length > 0);
  const longSentences = sentences.filter((s) => s.split(" ").length > 25);
  if (longSentences.length > sentences.length * 0.3) {
    issues.push("Many sentences are too long (>25 words)");
    suggestions.push(
      "Shorten sentences to 15-20 words for better AI extractability"
    );
    score -= 10;
  }

  return {
    score: Math.max(0, score),
    issues,
    suggestions,
  };
}
```

Now create `src/agents/aeo-auditor.ts` that uses this tool:

```typescript
import Anthropic from "@anthropic-ai/sdk";
import { validateAEOCompliance } from "../tools/aeo-validator";

const client = new Anthropic({
  apiKey: process.env.ANTHROPIC_API_KEY,
});

async function auditContent(content: string): Promise<void> {
  // First, validate with our custom tool
  const validation = await validateAEOCompliance(content);

  console.log(
    `\nAEO Compliance Score: ${validation.score}/100\n`
  );

  if (validation.issues.length > 0) {
    console.log("Issues Found:");
    validation.issues.forEach((issue) => console.log(`  - ${issue}`));
  }

  if (validation.suggestions.length > 0) {
    console.log("\nSuggestions:");
    validation.suggestions.forEach((sug) => console.log(`  - ${sug}`));
  }

  // Now use Claude to generate improvement recommendations
  const systemPrompt = `You are an AEO audit specialist. Based on the validation results, 
provide specific, actionable recommendations to improve AEO compliance.`;

  const messages: Anthropic.Messages.MessageParam[] = [
    {
      role: "user",
      content: `
Content to audit:
${content}

Validation Results:
Score: ${validation.score}/100
Issues: ${validation.issues.join(", ")}
Suggestions: ${validation.suggestions.join(", ")}

Please provide detailed improvement recommendations.`,
    },
  ];

  const response = await client.messages.create({
    model: "claude-opus-4-6",
    max_tokens: 1500,
    system: systemPrompt,
    messages: messages,
  });

  if (response.content[0].type === "text") {
    console.log("\n--- AUDIT RECOMMENDATIONS ---\n");
    console.log(response.content[0].text);
  }
}

// Usage
const sampleContent = `
# Understanding AEO for Modern Marketing

## What is Answer Engine Optimization?

Answer Engine Optimization (AEO) is the practice of optimizing content 
to be discovered and cited by AI-powered answer engines like ChatGPT, Claude, and Perplexity.

Unlike traditional SEO, which focuses on search engine rankings, AEO ensures 
your content is the source AI systems cite when answering user questions.

## Why AEO Matters

According to recent studies, 73% of professionals now use AI tools regularly. 
Companies that optimize for AEO see 40% higher content discovery.
`;

auditContent(sampleContent).catch(console.error);
```

