### Example 3: Agent with Tool Use (Streaming Responses)

Create `src/agents/research-agent.ts`:

```typescript
import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic({
  apiKey: process.env.ANTHROPIC_API_KEY,
});

// Define tools the agent can use
const tools: Anthropic.Messages.Tool[] = [
  {
    name: "search_web",
    description: "Search the web for information about a topic",
    input_schema: {
      type: "object" as const,
      properties: {
        query: {
          type: "string",
          description: "The search query",
        },
      },
      required: ["query"],
    },
  },
  {
    name: "analyze_content",
    description: "Analyze content for AEO optimization",
    input_schema: {
      type: "object" as const,
      properties: {
        content: {
          type: "string",
          description: "Content to analyze",
        },
        metrics: {
          type: "array",
          items: { type: "string" },
          description: "Metrics to check (e.g., readability, clarity)",
        },
      },
      required: ["content"],
    },
  },
];

async function runResearchAgent(query: string): Promise<void> {
  console.log(`Research Agent: ${query}\n`);

  const messages: Anthropic.Messages.MessageParam[] = [
    {
      role: "user",
      content: query,
    },
  ];

  let continueLoop = true;

  while (continueLoop) {
    const response = await client.messages.create({
      model: "claude-opus-4-6",
      max_tokens: 2000,
      tools: tools,
      messages: messages,
      system: `You are a research agent for CitedBy.ai. Your role is to research topics
and provide AEO-optimized analysis. Use available tools to gather information.`,
    });

    // Process the response
    for (const block of response.content) {
      if (block.type === "text") {
        console.log("Agent:", block.text);
      } else if (block.type === "tool_use") {
        console.log(`\nUsing tool: ${block.name}`);
        console.log("Input:", JSON.stringify(block.input, null, 2));

        // Simulate tool results
        let toolResult = "";
        if (block.name === "search_web") {
          toolResult = `Found 5 results for "${(block.input as any).query}"...`;
        } else if (block.name === "analyze_content") {
          toolResult = "Content analysis complete. Readability: Good, Clarity: Excellent";
        }

        // Add tool use and result to messages
        messages.push({
          role: "assistant",
          content: response.content,
        });
        messages.push({
          role: "user",
          content: [
            {
              type: "tool_result",
              tool_use_id: block.id,
              content: toolResult,
            },
          ],
        });
      }
    }

    // Check if we should continue
    if (response.stop_reason === "end_turn") {
      continueLoop = false;
    } else if (response.stop_reason === "tool_use") {
      // Continue the loop to process tool results
      continueLoop = true;
    } else {
      continueLoop = false;
    }
  }
}

// Usage
runResearchAgent(
  "Research AEO best practices and provide optimization recommendations"
).catch(console.error);
```

