### Example 4: Multi-Step Agentic Workflow

Create `src/agents/content-pipeline.ts`:

```typescript
import Anthropic from "@anthropic-ai/sdk";
import { validateAEOCompliance } from "../tools/aeo-validator";

const client = new Anthropic({
  apiKey: process.env.ANTHROPIC_API_KEY,
});

interface PipelineResult {
  originalContent: string;
  optimizedContent: string;
  validation: {
    originalScore: number;
    optimizedScore: number;
  };
}

async function contentOptimizationPipeline(
  topic: string,
  brand: string
): Promise<PipelineResult> {
  console.log("=== CONTENT OPTIMIZATION PIPELINE ===\n");

  // Step 1: Generate initial content
  console.log("Step 1: Generating initial content...");
  const initialMessages: Anthropic.Messages.MessageParam[] = [
    {
      role: "user",
      content: `Write a blog post about "${topic}" for ${brand}. 
      Include at least one H1, 2-3 H2s, and relevant data points.`,
    },
  ];

  const initialResponse = await client.messages.create({
    model: "claude-opus-4-6",
    max_tokens: 1500,
    system: `You are a content writer for ${brand}.`,
    messages: initialMessages,
  });

  const originalContent =
    initialResponse.content[0].type === "text" ? initialResponse.content[0].text : "";
  console.log("✓ Initial content generated\n");

  // Step 2: Validate original content
  console.log("Step 2: Validating original content...");
  const originalValidation = await validateAEOCompliance(originalContent);
  console.log(`  AEO Score: ${originalValidation.score}/100`);
  console.log(
    `  Issues: ${originalValidation.issues.length}\n`
  );

  // Step 3: Optimize for AEO
  console.log("Step 3: Optimizing for AEO...");
  const optimizationPrompt = `
You are an AEO specialist. Optimize this content for Answer Engine Optimization.

Original content:
${originalContent}

Issues to fix:
${originalValidation.issues.join("\n")}

Requirements:
- Clear H1 and H2 hierarchy
- Extractable paragraphs (under 50 words each)
- Include specific data/statistics
- Add FAQ section
- Ensure sentences are under 25 words

Provide ONLY the optimized content, ready to publish.`;

  const optimizationMessages: Anthropic.Messages.MessageParam[] = [
    {
      role: "user",
      content: optimizationPrompt,
    },
  ];

  const optimizationResponse = await client.messages.create({
    model: "claude-opus-4-6",
    max_tokens: 2000,
    system: "You are an expert AEO content optimizer.",
    messages: optimizationMessages,
  });

  const optimizedContent =
    optimizationResponse.content[0].type === "text"
      ? optimizationResponse.content[0].text
      : "";
  console.log("✓ Content optimized\n");

  // Step 4: Validate optimized content
  console.log("Step 4: Validating optimized content...");
  const optimizedValidation = await validateAEOCompliance(optimizedContent);
  console.log(`  AEO Score: ${optimizedValidation.score}/100\n`);

  // Step 5: Summary
  console.log("=== PIPELINE RESULTS ===");
  console.log(`Original Score: ${originalValidation.score}/100`);
  console.log(`Optimized Score: ${optimizedValidation.score}/100`);
  console.log(
    `Improvement: +${optimizedValidation.score - originalValidation.score} points\n`
  );

  return {
    originalContent,
    optimizedContent,
    validation: {
      originalScore: originalValidation.score,
      optimizedScore: optimizedValidation.score,
    },
  };
}

// Usage
contentOptimizationPipeline(
  "Future of AI in Content Marketing",
  "CitedBy.ai"
).catch(console.error);
```

