## 5. Advanced Patterns

### A. Running Agents Programmatically

Create `src/agents/runner.ts`:

```typescript
import Anthropic from "@anthropic-ai/sdk";
import { spawn } from "child_process";

const client = new Anthropic();

interface AgentConfig {
  name: string;
  model: string;
  systemPrompt: string;
  tools?: Anthropic.Messages.Tool[];
  maxIterations?: number;
}

class Agent {
  private config: AgentConfig;
  private messages: Anthropic.Messages.MessageParam[] = [];

  constructor(config: AgentConfig) {
    this.config = config;
  }

  async execute(userInput: string): Promise<string> {
    this.messages = [
      {
        role: "user",
        content: userInput,
      },
    ];

    let iterations = 0;
    const maxIterations = this.config.maxIterations || 10;

    while (iterations < maxIterations) {
      iterations++;

      const response = await client.messages.create({
        model: this.config.model,
        max_tokens: 4096,
        system: this.config.systemPrompt,
        tools: this.config.tools,
        messages: this.messages,
      });

      // Add assistant response to messages
      this.messages.push({
        role: "assistant",
        content: response.content,
      });

      // Check if we're done
      if (response.stop_reason === "end_turn") {
        // Extract final text response
        const finalText = response.content
          .filter((block) => block.type === "text")
          .map((block) => (block as any).text)
          .join("\n");

        return finalText;
      }

      // Handle tool use
      if (response.stop_reason === "tool_use") {
        const toolResults: Anthropic.Messages.ToolResultBlockParam[] = [];

        for (const block of response.content) {
          if (block.type === "tool_use") {
            // Execute tool (simplified example)
            let result = "Tool execution result";

            if (block.name === "bash") {
              result = await this.executeBash((block.input as any).command);
            }

            toolResults.push({
              type: "tool_result",
              tool_use_id: block.id,
              content: result,
            });
          }
        }

        this.messages.push({
          role: "user",
          content: toolResults,
        });
      }
    }

    throw new Error("Max iterations reached without completion");
  }

  private async executeBash(command: string): Promise<string> {
    return new Promise((resolve, reject) => {
      const proc = spawn("bash", ["-c", command]);
      let stdout = "";
      let stderr = "";

      proc.stdout.on("data", (data) => {
        stdout += data.toString();
      });

      proc.stderr.on("data", (data) => {
        stderr += data.toString();
      });

      proc.on("close", (code) => {
        if (code === 0) {
          resolve(stdout);
        } else {
          reject(new Error(`Command failed: ${stderr}`));
        }
      });
    });
  }
}

export { Agent, AgentConfig };
```

