### C. Agent with Memory/Context

Create `src/agents/memory-agent.ts`:

```typescript
import Anthropic from "@anthropic-ai/sdk";
import * as fs from "fs";
import * as path from "path";

interface Memory {
  conversations: Array<{
    id: string;
    timestamp: Date;
    topic: string;
    summary: string;
  }>;
  insights: string[];
  patterns: Record<string, any>;
}

class MemoryfulAgent {
  private memoryFile: string;
  private memory: Memory;
  private client: Anthropic;

  constructor(memoryPath: string = "./.memory.json") {
    this.memoryFile = memoryPath;
    this.client = new Anthropic();
    this.memory = this.loadMemory();
  }

  private loadMemory(): Memory {
    if (fs.existsSync(this.memoryFile)) {
      const data = fs.readFileSync(this.memoryFile, "utf-8");
      return JSON.parse(data);
    }

    return {
      conversations: [],
      insights: [],
      patterns: {},
    };
  }

  private saveMemory(): void {
    fs.writeFileSync(this.memoryFile, JSON.stringify(this.memory, null, 2));
  }

  async query(input: string): Promise<string> {
    // Build context from memory
    const contextPrompt = this.buildMemoryContext();

    const messages: Anthropic.Messages.MessageParam[] = [
      {
        role: "user",
        content: `
${contextPrompt}

Current query: ${input}

Based on previous conversations and insights, provide a response.`,
      },
    ];

    const response = await client.messages.create({
      model: "claude-opus-4-6",
      max_tokens: 1500,
      system: "You are an expert AEO specialist with historical knowledge of previous conversations.",
      messages,
    });

    const responseText =
      response.content[0].type === "text" ? response.content[0].text : "";

    // Store in memory
    this.memory.conversations.push({
      id: Date.now().toString(),
      timestamp: new Date(),
      topic: input.substring(0, 50),
      summary: responseText.substring(0, 200),
    });

    this.saveMemory();
    return responseText;
  }

  private buildMemoryContext(): string {
    let context = "";

    if (this.memory.insights.length > 0) {
      context += "Previous Insights:\n";
      context += this.memory.insights.join("\n");
      context += "\n\n";
    }

    if (this.memory.conversations.length > 5) {
      const recent = this.memory.conversations.slice(-5);
      context += "Recent Conversations:\n";
      recent.forEach((conv) => {
        context += `- ${conv.timestamp.toISOString()}: ${conv.topic}\n`;
      });
    }

    return context;
  }

  addInsight(insight: string): void {
    this.memory.insights.push(insight);
    this.saveMemory();
  }
}

export { MemoryfulAgent };
```

