## Complete Real-World Example: CitedBy.ai Content Generator Agent

Here's a production-ready agent for CitedBy.ai:

Create `src/agents/citedby-content-agent.ts`:

```typescript
import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic({
  apiKey: process.env.ANTHROPIC_API_KEY,
});

interface ContentGenerationRequest {
  brandName: string;
  productOrService: string;
  targetKeywords: string[];
  contentType:
    | "product_description"
    | "landing_page"
    | "blog_post"
    | "case_study";
  vertical:
    | "ecommerce"
    | "saas"
    | "immobilier"
    | "restauration"
    | "sante"
    | "finance"
    | "juridique"
    | "education"
    | "general";
  additionalContext?: string;
}

interface GeneratedContent {
  title: string;
  content: string;
  metaDescription: string;
  aeoScore: number;
  aeoTips: string[];
  schemaMarkup?: string;
}

async function generateCitedByContent(
  request: ContentGenerationRequest
): Promise<GeneratedContent> {
  const systemPrompt = `You are an expert AEO (Answer Engine Optimization) content specialist for CitedBy.ai.

Your expertise:
- Creating content specifically designed to be cited by AI engines (Claude, ChatGPT, Perplexity)
- Structuring content for maximum extractability
- Including citation-worthy data and insights
- Optimizing for both SEO and AI discovery

Brand Context: ${request.brandName}
Vertical: ${request.vertical}
Keywords: ${request.targetKeywords.join(", ")}

When generating content:
1. Start with a clear, direct answer/hook
2. Use H2 headings as questions
3. Keep paragraphs under 50 words for extractability
4. Include specific data/statistics (percentages, numbers, studies)
5. Structure with clear hierarchy: H1 > H2 > H3
6. Add FAQ section with 3-5 questions
7. Ensure each section is independently extractable by AI

Return ONLY the optimized content in Markdown format, no meta-commentary.`;

  const userPrompt = `Generate optimized content for CitedBy.ai:

Title/Topic: ${request.productOrService}
Content Type: ${request.contentType}
Brand: ${request.brandName}
Target Keywords: ${request.targetKeywords.join(", ")}
${request.additionalContext ? `Additional Context: ${request.additionalContext}` : ""}

Requirements:
- 1200-1500 words
- Clear H1, 3-4 H2 sections
- At least 3 data points/statistics
- FAQ section (3-5 questions)
- Tone: Professional, authoritative, citation-worthy
- Maximize AI discoverability`;

  const messages: Anthropic.Messages.MessageParam[] = [
    {
      role: "user",
      content: userPrompt,
    },
  ];

  try {
    const response = await client.messages.create({
      model: "claude-opus-4-6",
      max_tokens: 4000,
      system: systemPrompt,
      messages,
    });

    const content =
      response.content[0].type === "text" ? response.content[0].text : "";

    // Calculate basic AEO score
    const aeoScore = calculateAEOScore(content);

    // Extract title (first H1)
    const titleMatch = content.match(/^# (.+)/m);
    const title = titleMatch ? titleMatch[1] : request.productOrService;

    // Generate meta description
    const metaDescription = generateMetaDescription(title, content);

    // Generate schema markup
    const schemaMarkup = generateSchemaMarkup(request, title);

    // Extract AEO tips
    const aeoTips = extractAEOTips(content);

    return {
      title,
      content,
      metaDescription,
      aeoScore,
      aeoTips,
      schemaMarkup,
    };
  } catch (error) {
    console.error("Error generating content:", error);
    throw error;
  }
}

function calculateAEOScore(content: string): number {
  let score = 60; // Base score

  // Check for clear structure
  const h1Count = (content.match(/^# /gm) || []).length;
  const h2Count = (content.match(/^## /gm) || []).length;

  if (h1Count === 1) score += 10;
  if (h2Count >= 3) score += 10;

  // Check for data/statistics
  const dataPoints = (
    content.match(/(\d+%|\d+x|\$\d+|studies? show|research|data)/gi) || []
  ).length;
  if (dataPoints > 5) score += 10;

  // Check for FAQ
  if (content.toLowerCase().includes("faq") || content.includes("Q:")) {
    score += 5;
  }

  // Check sentence length
  const sentences = content.split(/[.!?]+/).filter((s) => s.trim().length > 0);
  const longSentences = sentences.filter((s) => s.split(" ").length > 25);
  const shortSentenceRatio = (sentences.length - longSentences.length) / sentences.length;

  if (shortSentenceRatio > 0.7) score += 5;

  return Math.min(100, score);
}

function generateMetaDescription(title: string, content: string): string {
  // Extract first substantial paragraph
  const paragraphs = content
    .split("\n\n")
    .filter((p) => !p.startsWith("#") && p.trim().length > 0);

  let description = title;
  if (paragraphs.length > 0) {
    const firstPara = paragraphs[0]
      .replace(/[\*\[\]\(\)]/g, "")
      .substring(0, 150);
    description = firstPara.length > 0 ? firstPara : title;
  }

  return description.substring(0, 160);
}

function generateSchemaMarkup(
  request: ContentGenerationRequest,
  title: string
): string {
  return JSON.stringify(
    {
      "@context": "https://schema.org",
      "@type": "Article",
      headline: title,
      description: `AEO-optimized content about ${request.productOrService}`,
      author: {
        "@type": "Organization",
        name: request.brandName,
      },
      publisher: {
        "@type": "Organization",
        name: "CitedBy.ai",
        logo: {
          "@type": "ImageObject",
          url: "https://citedby.ai/logo.png",
        },
      },
      datePublished: new Date().toISOString(),
      keywords: request.targetKeywords.join(", "),
      inLanguage: "en",
    },
    null,
    2
  );
}

function extractAEOTips(content: string): string[] {
  const tips: string[] = [];

  if ((content.match(/^## /gm) || []).length < 3) {
    tips.push("Add more H2 sections for better structure");
  }

  if (!content.includes("FAQ") && !content.toLowerCase().includes("question")) {
    tips.push("Consider adding an FAQ section");
  }

  const sentences = content
    .split(/[.!?]+/)
    .filter((s) => s.trim().length > 0);
  const avgLength =
    sentences.reduce((sum, s) => sum + s.split(" ").length, 0) /
    sentences.length;
  if (avgLength > 20) {
    tips.push("Shorten sentences for better AI extractability");
  }

  const dataMatches = (
    content.match(/(\d+%|\d+x|\$\d+|research|studies show)/gi) || []
  ).length;
  if (dataMatches < 3) {
    tips.push("Add more statistics and data points");
  }

  return tips;
}

// Export for use
export { generateCitedByContent, GeneratedContent, ContentGenerationRequest };

// Usage example
if (require.main === module) {
  generateCitedByContent({
    brandName: "CitedBy.ai",
    productOrService: "AEO Optimization Platform",
    targetKeywords: [
      "AEO",
      "answer engine optimization",
      "AI citation",
      "content optimization",
    ],
    contentType: "blog_post",
    vertical: "saas",
    additionalContext:
      "Focus on why AEO is critical in 2026 and how it differs from traditional SEO",
  })
    .then((result) => {
      console.log("=== GENERATED CONTENT ===\n");
      console.log(result.content);
      console.log("\n=== METADATA ===");
      console.log(`Title: ${result.title}`);
      console.log(`AEO Score: ${result.aeoScore}/100`);
      console.log(`Meta Description: ${result.metaDescription}`);
      console.log("\nAEO Tips:");
      result.aeoTips.forEach((tip) => console.log(`  - ${tip}`));
    })
    .catch(console.error);
}
